function getPreco(produto, tamanho) {
  const p = produto.precos;
  if (p.all) return p.all;
  if (tamanho === "EGG") return p.EGG || p.EG || p["P-GG"];
  if (tamanho === "XG")  return p.XG  || p["P-GG"];
  if (tamanho === "EG")  return p.EG  || p["P-GG"];
  return p["P-GG"] || 0;
}

