// Use Supabase JS SDK via CDN
let _supa = null;
async function getSupa() {
  if (_supa) return _supa;
  const { createClient } = await import("https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/+esm");
  _supa = createClient(SUPA_URL, SUPA_KEY);
  return _supa;
}

async function supaFetch(path, options = {}) {
  // Fallback raw fetch for compatibility
  const res = await fetch(`${SUPA_URL}/rest/v1${path}`, {
    ...options,
    headers: {
      "apikey": SUPA_KEY,
      "Authorization": `Bearer ${SUPA_KEY}`,
      "Content-Type": "application/json",
      "Prefer": options.prefer || "return=representation",
      ...options.headers,
    },
  });
  if (!res.ok) {
    const err = await res.text();
    throw new Error(err);
  }
  const text = await res.text();
  return text ? JSON.parse(text) : null;
}

// Config helpers
async function getConfig(chave) {
  try {
    const db = await getSupa();
    const { data } = await db.from("config").select("valor").eq("chave", chave).single();
    return data?.valor ?? "";
  } catch { return ""; }
}

async function setConfig(chave, valor) {
  try {
    const db = await getSupa();
    await db.from("config").update({ valor }).eq("chave", chave);
  } catch(e) { console.error("setConfig error", e); }
}

async function getPedidos(etapa) {
  try {
    const db = await getSupa();
    const { data } = await db.from("pedidos").select("*").eq("etapa", etapa).order("data", { ascending: false });
    return data || [];
  } catch { return []; }
}

async function addPedido(pedido) {
  try {
    const db = await getSupa();
    const { error } = await db.from("pedidos").insert(pedido);
    if(error) console.error("addPedido error", error);
  } catch(e) { console.error("addPedido error", e); }
}

async function updatePedidoPago(id, pago) {
  try {
    const db = await getSupa();
    await db.from("pedidos").update({ pago }).eq("id", id);
  } catch(e) { console.error("updatePedidoPago error", e); }
}

async function deletePedidosByEtapa(etapa) {
  try {
    const db = await getSupa();
    await db.from("pedidos").delete().eq("etapa", etapa);
  } catch(e) { console.error("deletePedidosByEtapa error", e); }
}

