// ── QR Code Pix ───────────────────────────────────────────────────
function pixPayload(chave,nome,cidade){
  const field=(id,val)=>`${id}${String(val).length.toString().padStart(2,"0")}${val}`;
  const ma=field("00","BR.GOV.BCB.PIX")+field("01",chave);
  let p=field("00","01")+field("26",ma)+"5204000053039865802BR"+field("59",nome.slice(0,25))+field("60",cidade.slice(0,15))+field("62",field("05","***"))+"6304";
  let crc=0xFFFF;
  for(const c of p){crc^=c.charCodeAt(0)<<8;for(let i=0;i<8;i++)crc=crc&0x8000?(crc<<1)^0x1021:(crc<<1);crc&=0xFFFF;}
  return p+crc.toString(16).toUpperCase().padStart(4,"0");
}
const PIX_PAYLOAD=pixPayload("financasejcmedeiros@gmail.com","EJC Medeiros","Sao Paulo");
const QR_URL=`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(PIX_PAYLOAD)}`;

// ── Formulário ────────────────────────────────────────────────────
function FormPedido({onPedidoAdicionado,etapa,equipes,encerrado,prazoInfo}) {
  const emptyItem=()=>({id:gerarId(),produto:"",tamanho:"",gola:"",cor:"",quantidade:1,estampa:"Padrão"});
  const [nome,setNome]=useState("");
  const [tel,setTel]=useState("");
  const [equipe,setEquipe]=useState("");
  const [itens,setItens]=useState([emptyItem()]);
  const [passo,setPasso]=useState("form");
  const [erro,setErro]=useState("");
  const [pedidoAtual,setPedidoAtual]=useState(null);
  const [agoraPrazo,setAgoraPrazo]=useState(new Date());

  useEffect(()=>{
    if(!prazoInfo) return;
    const iv=setInterval(()=>setAgoraPrazo(new Date()),1000);
    return()=>clearInterval(iv);
  },[prazoInfo]);

  const countdownPrazo=prazoInfo?(()=>{
    const ms=new Date(prazoInfo)-agoraPrazo;
    if(ms<=0) return "Encerrado";
    const d=Math.floor(ms/86400000),h=Math.floor((ms%86400000)/3600000),m=Math.floor((ms%3600000)/60000),s=Math.floor((ms%60000)/1000);
    if(d>0) return `${d}d ${h}h ${m}m`;
    return `${h.toString().padStart(2,"0")}:${m.toString().padStart(2,"0")}:${s.toString().padStart(2,"0")}`;
  })():"";

  const addItem=()=>setItens([...itens,emptyItem()]);
  const removeItem=id=>setItens(itens.filter(i=>i.id!==id));
  const updateItem=(id,field,value)=>setItens(itens.map(i=>{
    if(i.id!==id) return i;
    const u={...i,[field]:value};
    if(field==="produto"){
      u.tamanho="";u.gola="";
      const np=PRODUTOS.find(p=>p.tipo===value);
      if(np?.coresExcluidas?.includes(u.cor)) u.cor="";
    }
    if(field==="cor"&&value!=="Preto") u.estampa="Padrão";
    return u;
  }));
  const getProduto=tipo=>PRODUTOS.find(p=>p.tipo===tipo);
  const total=itens.reduce((acc,item)=>{
    const p=getProduto(item.produto);
    if(!p||!item.tamanho) return acc;
    return acc+getPreco(p,item.tamanho)*item.quantidade;
  },0);

  const avancar=async()=>{
    setErro("");
    if(encerrado) return setErro("Os pedidos desta etapa estão encerrados.");
    if(!nome.trim()) return setErro("Informe seu nome.");
    if(!tel.trim())  return setErro("Informe seu WhatsApp.");
    if(!equipe)      return setErro("Selecione sua equipe.");
    for(const item of itens){
      if(!item.produto||!item.tamanho||!item.cor||!item.quantidade)
        return setErro("Preencha todos os campos de cada item.");
    }
    const pedido={id:gerarId(),nome:nome.trim(),tel:tel.trim(),equipe,etapa,itens,total,pago:false};
    await addPedido(pedido);
    onPedidoAdicionado(pedido);
    setPedidoAtual(pedido);
    setPasso("pix");
  };

  const finalizar=()=>{
    setNome("");setTel("");setEquipe("");setItens([emptyItem()]);
    setPasso("ok");
    setTimeout(()=>setPasso("form"),4000);
  };

  if(passo==="ok") return (
    <div style={{textAlign:"center",padding:"60px 20px"}}>
      <div style={{fontSize:64,marginBottom:16}}>🎉</div>
      <div style={{fontSize:24,fontWeight:800,color:C.green,marginBottom:8}}>Pedido registrado!</div>
      <div style={{color:C.muted,fontSize:14}}>Obrigado, {pedidoAtual?.nome}!</div>
    </div>
  );

  if(passo==="pix") return (
    <div style={{maxWidth:380,margin:"0 auto",padding:"20px 0"}}>
      <div style={{textAlign:"center",marginBottom:20}}>
        <div style={{fontSize:13,color:C.muted,marginBottom:4}}>Pedido de <strong style={{color:C.text}}>{pedidoAtual?.nome}</strong></div>
        <div style={{fontSize:28,fontWeight:800,color:C.green}}>R$ {total.toFixed(2).replace(".",",")}</div>
      </div>
      <Card style={{marginBottom:16,textAlign:"center"}}>
        <Badge color={C.green}>PAGUE VIA PIX</Badge>
        <div style={{margin:"16px 0"}}>
          <div style={{background:"#fff",borderRadius:12,padding:10,display:"inline-block",boxShadow:glow(C.accent)}}>
            <img src={QR_URL} alt="QR Pix" width={180} height={180} style={{display:"block",borderRadius:6}}/>
          </div>
        </div>
        <div style={{fontSize:11,color:C.muted,marginBottom:12}}>financasejcmedeiros@gmail.com</div>
        <GhostBtn onClick={()=>navigator.clipboard?.writeText(PIX_PAYLOAD)} color={C.muted} style={{fontSize:12,padding:"7px 14px"}}>
          📋 Copiar código Pix
        </GhostBtn>
      </Card>
      <Card style={{marginBottom:16,fontSize:12,color:C.muted,lineHeight:1.7,textAlign:"center"}}>
        Após pagar, toque em <strong style={{color:C.text}}>"Já paguei"</strong>.<br/>O coordenador confirma no painel.
      </Card>
      <div style={{display:"flex",gap:10}}>
        <GhostBtn onClick={()=>setPasso("form")} style={{flex:1}}>Voltar</GhostBtn>
        <PrimaryBtn onClick={finalizar} style={{flex:2}}>✓ Já paguei</PrimaryBtn>
      </div>
    </div>
  );

  const inpDark={...inp};

  return (
    <div>
      {!encerrado && prazoInfo && (
        <div style={{background:`${C.accent}15`,border:`1px solid ${C.accent}55`,borderRadius:14,padding:"14px 18px",marginBottom:20,display:"flex",alignItems:"center",gap:14}}>
          <div style={{fontSize:28}}>⏰</div>
          <div style={{flex:1}}>
            <div style={{fontSize:11,fontWeight:800,letterSpacing:1,color:C.accent,marginBottom:3}}>PRAZO PARA PEDIDOS</div>
            <div style={{fontSize:12,color:C.muted,marginBottom:2}}>{new Date(prazoInfo).toLocaleString("pt-BR",{weekday:"long",day:"2-digit",month:"long",hour:"2-digit",minute:"2-digit"})}</div>
            <div style={{fontSize:20,fontWeight:800,color:C.accent,fontFamily:"monospace"}}>{countdownPrazo}</div>
          </div>
        </div>
      )}
      {encerrado && (
        <div style={{background:`${C.pink}15`,border:`2px solid ${C.pink}`,borderRadius:14,padding:"24px 20px",marginBottom:24,textAlign:"center"}}>
          <div style={{fontSize:40,marginBottom:8}}>🔴</div>
          <div style={{fontSize:20,fontWeight:800,color:C.pink,marginBottom:6}}>Pedidos encerrados</div>
          <div style={{fontSize:13,color:C.muted}}>O prazo desta etapa foi encerrado.<br/>Entre em contato com o coordenador.</div>
        </div>
      )}
      {erro && <div style={{background:`${C.pink}15`,border:`1px solid ${C.pink}55`,borderRadius:10,padding:"12px 16px",marginBottom:16,color:C.pink,fontSize:13}}>⚠ {erro}</div>}

      <div style={{opacity:encerrado?0.4:1,pointerEvents:encerrado?"none":"auto"}}>
        <SectionTitle>Seus dados</SectionTitle>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
          <div>
            <label style={{fontSize:10,color:C.muted,display:"block",marginBottom:5,letterSpacing:1,fontWeight:700}}>NOME COMPLETO</label>
            <input style={inpDark} value={nome} onChange={e=>setNome(e.target.value)} placeholder="Seu nome"/>
          </div>
          <div>
            <label style={{fontSize:10,color:C.muted,display:"block",marginBottom:5,letterSpacing:1,fontWeight:700}}>WHATSAPP</label>
            <input style={inpDark} value={tel} onChange={e=>setTel(e.target.value)} placeholder="(11) 99999-9999" type="tel"/>
          </div>
        </div>
        <div style={{marginBottom:20}}>
          <label style={{fontSize:10,color:C.muted,display:"block",marginBottom:5,letterSpacing:1,fontWeight:700}}>EQUIPE</label>
          <select style={inpDark} value={equipe} onChange={e=>setEquipe(e.target.value)}>
            <option value="">Selecione sua equipe...</option>
            {equipes.map(eq=><option key={eq} value={eq}>{eq}</option>)}
          </select>
        </div>

        <SectionTitle>Itens do pedido</SectionTitle>
        {itens.map((item,idx)=>{
          const prod=getProduto(item.produto);
          return (
            <Card key={item.id} style={{marginBottom:12,border:`1px solid ${C.border}`}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
                <Badge color={C.accent}>Item {idx+1}</Badge>
                {itens.length>1&&<button onClick={()=>removeItem(item.id)} style={{background:"none",border:"none",color:C.muted,cursor:"pointer",fontSize:18,padding:0}}>×</button>}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:10}}>
                {[
                  {label:"TIPO DE PEÇA", val:item.produto, field:"produto", opts:PRODUTOS.map(p=>({v:p.tipo,l:p.tipo}))},
                  {label:"TAMANHO",      val:item.tamanho, field:"tamanho", opts:prod?prod.tamanhos.map(t=>({v:t,l:t})):[]},
                  {label:"GOLA",         val:item.gola,    field:"gola",    opts:prod?prod.golas.map(g=>({v:g,l:g})):[]},
                ].map(f=>(
                  <div key={f.field}>
                    <label style={{fontSize:9,color:C.muted,display:"block",marginBottom:4,letterSpacing:1,fontWeight:700}}>{f.label}</label>
                    <select style={inpDark} value={f.val} onChange={e=>updateItem(item.id,f.field,e.target.value)} disabled={f.field!=="produto"&&!prod}>
                      <option value="">—</option>
                      {f.opts.map(o=><option key={o.v} value={o.v}>{o.l}</option>)}
                    </select>
                  </div>
                ))}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 70px",gap:10,marginBottom:10}}>
                <div>
                  <label style={{fontSize:9,color:C.muted,display:"block",marginBottom:4,letterSpacing:1,fontWeight:700}}>COR</label>
                  <select style={inpDark} value={item.cor} onChange={e=>updateItem(item.id,"cor",e.target.value)}>
                    <option value="">Selecione...</option>
                    {CORES.filter(c=>!(prod?.coresExcluidas||[]).includes(c.nome)).map(c=><option key={c.nome} value={c.nome}>{c.nome}</option>)}
                  </select>
                </div>
                <div>
                  <label style={{fontSize:9,color:C.muted,display:"block",marginBottom:4,letterSpacing:1,fontWeight:700}}>QTD</label>
                  <input type="number" min={1} max={100} style={inpDark} value={item.quantidade} onChange={e=>updateItem(item.id,"quantidade",parseInt(e.target.value)||1)}/>
                </div>
              </div>
              {/* Estampa */}
              <div style={{background:item.cor==="Preto"?`${C.pink}12`:`${C.border}44`,border:`1px solid ${item.cor==="Preto"?C.pink:C.border}`,borderRadius:10,padding:"10px 12px",display:"flex",alignItems:"center",gap:14,flexWrap:"wrap"}}>
                <span style={{fontSize:10,fontWeight:800,letterSpacing:1,color:item.cor==="Preto"?C.pink:C.muted}}>🎨 ESTAMPA</span>
                <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:13,color:item.estampa!=="Pink"?C.text:C.muted}}>
                  <input type="radio" name={"estampa-"+item.id} checked={item.estampa!=="Pink"} onChange={()=>updateItem(item.id,"estampa","Padrão")} disabled={item.cor!=="Preto"} style={{accentColor:C.accent,width:16,height:16}}/>
                  Padrão
                </label>
                {item.cor==="Preto"&&(
                  <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:13,color:item.estampa==="Pink"?C.pink:C.muted}}>
                    <input type="radio" name={"estampa-"+item.id} checked={item.estampa==="Pink"} onChange={()=>updateItem(item.id,"estampa","Pink")} style={{accentColor:C.pink,width:16,height:16}}/>
                    Pink ✨
                  </label>
                )}
                {item.cor!=="Preto"&&<span style={{fontSize:11,color:C.muted,fontStyle:"italic"}}>Disponível só no Preto</span>}
              </div>
              {prod&&item.tamanho&&(
                <div style={{textAlign:"right",marginTop:8,color:C.green,fontWeight:800,fontSize:15}}>
                  R$ {(getPreco(prod,item.tamanho)*item.quantidade).toFixed(2).replace(".",",")}
                </div>
              )}
            </Card>
          );
        })}

        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:16,gap:10}}>
          <GhostBtn onClick={addItem} color={C.accent} style={{fontSize:13,padding:"10px 16px"}}>+ Item</GhostBtn>
          <div style={{display:"flex",alignItems:"center",gap:16}}>
            <div style={{color:C.green,fontWeight:800,fontSize:17}}>R$ {total.toFixed(2).replace(".",",")}</div>
            <PrimaryBtn onClick={avancar}>Pagar com Pix →</PrimaryBtn>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Painel Admin ──────────────────────────────────────────────────
function PainelAdmin({pedidos,etapa,onLimpar,onTogglePago,savePedidos,etapaLock,onLockChange}) {
  const [senha,setSenha]=useState("");
  const [auth,setAuth]=useState(false);
  const [errSenha,setErrSenha]=useState(false);
  const SENHA=getSenhaAdmin();
  const SENHA_RESET=getSenhaDir();

  const [showReset,setShowReset]=useState(false);
  const [senhaReset,setSenhaReset]=useState("");
  const [errReset,setErrReset]=useState(false);

  const [showTimer,setShowTimer]=useState(false);
  const [senhaTimer,setSenhaTimer]=useState("");
  const [errSenhaTimer,setErrSenhaTimer]=useState(false);
  const [timerInput,setTimerInput]=useState("");
  const [timerAtivo,setTimerAtivo]=useState(()=>loadTimer(etapa||1));
  const [agora,setAgora]=useState(new Date());
  const [encerrado,setEncerrado]=useState(false);

  const [showLockModal,setShowLockModal]=useState(false);
  const [senhaLock,setSenhaLock]=useState("");
  const [errSenhaLock,setErrSenhaLock]=useState(false);
  const [lockTarget,setLockTarget]=useState("");

  const [showTrocarSenha,setShowTrocarSenha]=useState(false);
  const [tipoTroca,setTipoTroca]=useState("admin");
  const [senhaAtual,setSenhaAtual]=useState("");
  const [senhaNova,setSenhaNova]=useState("");
  const [senhaNovaConf,setSenhaNovaConf]=useState("");
  const [errTroca,setErrTroca]=useState("");
  const [okTroca,setOkTroca]=useState(false);

  useEffect(()=>{
    const iv=setInterval(()=>setAgora(new Date()),1000);
    return()=>clearInterval(iv);
  },[]);

  useEffect(()=>{
    const t=loadTimer(etapa||1);
    setTimerAtivo(t);
    setEncerrado(t?new Date()>=new Date(t):false);
  },[etapa]);

  const prazo=timerAtivo?new Date(timerAtivo):null;
  const diff=prazo?prazo-agora:null;
  const estaEncerrado=prazo?agora>=prazo:false;

  const formatCountdown=(ms)=>{
    if(ms<=0) return "Encerrado";
    const d=Math.floor(ms/86400000),h=Math.floor((ms%86400000)/3600000),m=Math.floor((ms%3600000)/60000),s=Math.floor((ms%60000)/1000);
    if(d>0) return `${d}d ${h}h ${m}m`;
    return `${h.toString().padStart(2,"0")}:${m.toString().padStart(2,"0")}:${s.toString().padStart(2,"0")}`;
  };

  const salvarTimer=async()=>{
    if(senhaTimer!==getSenhaDir()){setErrSenhaTimer(true);return;}
    if(!timerInput) return;
    await setConfig(`timer_etapa${etapa}`, timerInput);
    setTimerAtivo(timerInput);
    setShowTimer(false);setSenhaTimer("");setErrSenhaTimer(false);setTimerInput("");
  };
  const cancelarTimer=async()=>{
    if(senhaTimer!==getSenhaDir()){setErrSenhaTimer(true);return;}
    await setConfig(`timer_etapa${etapa}`, "");
    setTimerAtivo("");setTimerInput("");
    setShowTimer(false);setSenhaTimer("");setErrSenhaTimer(false);
  };
  const confirmarReset=async()=>{
    if(senhaReset!==getSenhaDir()){setErrReset(true);return;}
    await deletePedidosByEtapa(etapa);
    setShowReset(false);setSenhaReset("");setErrReset(false);
    onLimpar();
  };
  const confirmarTroca=async()=>{
    setErrTroca("");
    const sc=tipoTroca==="admin"?getSenhaAdmin():getSenhaDir();
    if(senhaAtual!==sc) return setErrTroca("Senha atual incorreta.");
    if(senhaNova.length<6) return setErrTroca("Mínimo 6 caracteres.");
    if(senhaNova!==senhaNovaConf) return setErrTroca("Senhas não coincidem.");
    const chave = tipoTroca==="admin" ? "senha_admin" : "senha_dir";
    if(tipoTroca==="admin") setSenhaAdmin(senhaNova);
    else setSenhaDir(senhaNova);
    await setConfig(chave, senhaNova);
    setOkTroca(true);
    setSenhaAtual("");setSenhaNova("");setSenhaNovaConf("");
    setTimeout(()=>{setOkTroca(false);setShowTrocarSenha(false);},2000);
  };
  const confirmarLock=async()=>{
    if(senhaLock!==getSenhaDir()){setErrSenhaLock(true);return;}
    await setConfig("etapa_lock", lockTarget);
    onLockChange(lockTarget);
    setShowLockModal(false);setSenhaLock("");setErrSenhaLock(false);
  };

  // Load senhas from Supabase when authenticated
  useEffect(()=>{
    if(!auth) return;
    async function loadSenhas() {
      const [sa, sd] = await Promise.all([
        getConfig("senha_admin"),
        getConfig("senha_dir"),
      ]);
      if(sa) setSenhaAdmin(sa);
      if(sd) setSenhaDir(sd);
      // Also load timer
      const t = await getConfig(`timer_etapa${etapa}`);
      setTimerAtivo(t||"");
      // Load lock
      const lock = await getConfig("etapa_lock");
      // Reload pedidos
    }
    loadSenhas();
  },[auth, etapa]);

  if(!auth) return (
    <div style={{maxWidth:360}}>
      <div style={{marginBottom:24,textAlign:"center"}}>
        <div style={{fontSize:48,marginBottom:8}}>🔐</div>
        <div style={{fontSize:22,fontWeight:800,color:C.text,marginBottom:4}}>Acesso restrito</div>
        <div style={{fontSize:13,color:C.muted}}>Apenas coordenadores autorizados.</div>
      </div>
      <label style={{fontSize:10,color:C.muted,display:"block",marginBottom:6,letterSpacing:1,fontWeight:700}}>SENHA DE ACESSO</label>
      <div style={{display:"flex",gap:8}}>
        <input type="password" value={senha} onChange={e=>setSenha(e.target.value)}
          onKeyDown={e=>e.key==="Enter"&&(senha===SENHA?setAuth(true):setErrSenha(true))}
          style={{...inp,flex:1}} placeholder="••••••••"/>
        <PrimaryBtn onClick={()=>senha===SENHA?setAuth(true):setErrSenha(true)}>Entrar</PrimaryBtn>
      </div>
      {errSenha&&<div style={{color:C.pink,fontSize:12,marginTop:8}}>Senha incorreta. Tente novamente.</div>}
    </div>
  );

  const totalPecas=pedidos.reduce((a,p)=>a+p.itens.reduce((b,i)=>b+i.quantidade,0),0);
  const totalValor=pedidos.reduce((a,p)=>a+p.total,0);
  const totalPago=pedidos.filter(p=>p.pago).reduce((a,p)=>a+p.total,0);
  const pendente=totalValor-totalPago;

  const porItem={};
  pedidos.forEach(p=>p.itens.forEach(item=>{
    const k=`${item.produto}|${item.tamanho}|${item.gola}|${item.cor}|${item.cor==="Preto"?(item.estampa||"Padrão"):"Padrão"}`;
    if(!porItem[k]) porItem[k]={...item,estampaLabel:item.cor==="Preto"?(item.estampa||"Padrão"):"—",quantidade:0};
    porItem[k].quantidade+=item.quantidade;
  }));
  const resumo=Object.values(porItem).sort((a,b)=>b.quantidade-a.quantidade);

  const exportCSV=(rows,filename)=>{
    const blob=new Blob([rows.join("\n")],{type:"text/csv;charset=utf-8;"});
    const a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download=filename;a.click();
  };
  const exportarTudo=()=>exportCSV([
    ["Nome","Contato","Equipe","Produto","Tamanho","Gola","Cor","Estampa","Qtd","Preço unit.","Subtotal","Pago","Data"].join(";"),
    ...pedidos.flatMap(p=>p.itens.map(item=>{
      const prod=PRODUTOS.find(x=>x.tipo===item.produto);
      const preco=prod?getPreco(prod,item.tamanho):0;
      return [p.nome,p.tel||"",p.equipe,item.produto,item.tamanho,item.gola,item.cor,item.cor==="Preto"?(item.estampa||"Padrão"):"Padrão",item.quantidade,preco,preco*item.quantidade,p.pago?"Sim":"Não",new Date(p.data).toLocaleString("pt-BR")].join(";");
    }))
  ],"pedidos_ejc.csv");
  const exportarPecas=()=>exportCSV([
    ["Produto","Tamanho","Gola","Cor","Quantidade Total"].join(";"),
    ...resumo.map(r=>[r.produto,r.tamanho,r.gola,r.cor,r.quantidade].join(";"))
  ],"fornecedor_pecas.csv");
  const exportarEstampas=()=>{
    const m={};
    pedidos.forEach(p=>p.itens.forEach(i=>{
      const k=`${i.cor}|${i.produto}|${i.tamanho}`;
      if(!m[k]) m[k]={cor:i.cor,produto:i.produto,tamanho:i.tamanho,quantidade:0};
      m[k].quantidade+=i.quantidade;
    }));
    exportCSV([["Cor","Produto","Tamanho","Qtd estampar"].join(";"),...Object.values(m).map(r=>[r.cor,r.produto,r.tamanho,r.quantidade].join(";"))],"fornecedor_estampas.csv");
  };

  const ActionBtn=({onClick,children,color})=>(
    <button onClick={onClick} style={{
      background:`${color}22`,color,border:`1px solid ${color}55`,
      borderRadius:10,padding:"10px 14px",cursor:"pointer",fontWeight:700,fontSize:12,
      display:"flex",alignItems:"center",gap:6,whiteSpace:"nowrap",
    }}>{children}</button>
  );

  return (
    <div>
      {/* Cards */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:12,marginBottom:24}}>
        {[
          {label:"Pedidos",   valor:pedidos.length, cor:C.accent},
          {label:"Peças",     valor:totalPecas,     cor:C.blue},
          {label:"Total",     valor:`R$ ${totalValor.toFixed(2).replace(".",",")}`, cor:C.green},
          {label:"A receber", valor:`R$ ${pendente.toFixed(2).replace(".",",")}`,   cor:C.pink},
        ].map(c=>(
          <Card key={c.label} style={{padding:"14px 16px"}}>
            <div style={{fontSize:9,color:C.muted,letterSpacing:1.5,marginBottom:6,fontWeight:700}}>{c.label.toUpperCase()}</div>
            <div style={{fontSize:22,fontWeight:800,color:c.cor,textShadow:`0 0 20px ${c.cor}60`}}>{c.valor}</div>
          </Card>
        ))}
      </div>

      {/* Timer */}
      <Card style={{marginBottom:16,border:`1px solid ${estaEncerrado?C.pink:timerAtivo?C.green:C.border}`}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:10}}>
          <div>
            <div style={{fontSize:10,fontWeight:800,letterSpacing:2,color:estaEncerrado?C.pink:timerAtivo?C.green:C.muted,marginBottom:4}}>
              {estaEncerrado?"🔴 ENCERRADO":timerAtivo?"🟢 PRAZO ATIVO":"⚪ SEM PRAZO"}
            </div>
            {timerAtivo&&(
              <div>
                <div style={{fontSize:11,color:C.muted,marginBottom:2}}>{new Date(timerAtivo).toLocaleString("pt-BR")}</div>
                <div style={{fontSize:20,fontWeight:800,color:estaEncerrado?C.pink:C.green,fontFamily:"monospace"}}>
                  {estaEncerrado?"⛔ Encerrado":formatCountdown(diff)}
                </div>
              </div>
            )}
            {!timerAtivo&&<div style={{fontSize:12,color:C.muted}}>Defina um prazo de encerramento.</div>}
          </div>
          <PrimaryBtn onClick={()=>{setShowTimer(true);setSenhaTimer("");setErrSenhaTimer(false);setTimerInput(timerAtivo||"");}} color={C.green} style={{fontSize:12,padding:"8px 14px"}}>
            {timerAtivo?"✏️ Editar":"📅 Definir"}
          </PrimaryBtn>
        </div>
      </Card>

      {/* Trava */}
      <Card style={{marginBottom:16,border:`1px solid ${etapaLock?C.blue:C.border}`}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:10}}>
          <div>
            <div style={{fontSize:10,fontWeight:800,letterSpacing:2,color:etapaLock?C.blue:C.muted,marginBottom:4}}>
              {etapaLock?`🔒 TRAVADO — ${etapaLock}ª ETAPA`:"🔓 ETAPA LIVRE"}
            </div>
            <div style={{fontSize:12,color:C.muted}}>
              {etapaLock?`Apenas ${etapaLock}ª etapa disponível.`:"Participantes trocam livremente."}
            </div>
          </div>
          <div style={{display:"flex",gap:8}}>
            {[1,2].map(e=>(
              <button key={e} onClick={()=>{setLockTarget(String(e));setShowLockModal(true);setSenhaLock("");setErrSenhaLock(false);}} style={{
                background:etapaLock===String(e)?`${C.blue}33`:`${C.border}33`,
                color:etapaLock===String(e)?C.blue:C.muted,
                border:`1px solid ${etapaLock===String(e)?C.blue:C.border}`,
                borderRadius:8,padding:"8px 12px",cursor:"pointer",fontWeight:700,fontSize:12,
              }}>{etapaLock===String(e)?"🔒":"🔓"} {e}ª</button>
            ))}
            {etapaLock&&(
              <button onClick={()=>{setLockTarget("");setShowLockModal(true);setSenhaLock("");setErrSenhaLock(false);}} style={{
                background:`${C.pink}22`,color:C.pink,border:`1px solid ${C.pink}55`,
                borderRadius:8,padding:"8px 12px",cursor:"pointer",fontWeight:700,fontSize:12,
              }}>🔓</button>
            )}
          </div>
        </div>
      </Card>

      {/* Ações */}
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:24}}>
        <ActionBtn onClick={exportarTudo}     color={C.muted}>⬇ Tudo</ActionBtn>
        <ActionBtn onClick={exportarPecas}    color={C.blue}>⬇ Peças</ActionBtn>
        <ActionBtn onClick={exportarEstampas} color="#AA44FF">⬇ Estampas</ActionBtn>
        <ActionBtn onClick={()=>{setShowTrocarSenha(true);setTipoTroca("admin");setSenhaAtual("");setSenhaNova("");setSenhaNovaConf("");setErrTroca("");setOkTroca(false);}} color={C.green}>🔑 Senhas</ActionBtn>
        <ActionBtn onClick={()=>setShowReset(true)} color={C.pink}>🗑 Resetar</ActionBtn>
      </div>

      {/* Resumo por item */}
      <SectionTitle>Resumo por item</SectionTitle>
      <div style={{overflowX:"auto",marginBottom:24}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
          <thead>
            <tr style={{background:C.card2}}>
              {["Produto","Tam.","Gola","Cor","Estampa","Qtd"].map(h=>(
                <th key={h} style={{padding:"8px 10px",textAlign:"left",color:C.accent,fontSize:10,letterSpacing:1,fontWeight:800}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {resumo.length===0
              ?<tr><td colSpan={6} style={{padding:16,color:C.muted,textAlign:"center",fontSize:13}}>Nenhum pedido ainda.</td></tr>
              :resumo.map((r,i)=>(
                <tr key={i} style={{background:i%2===0?C.card:C.card2,borderBottom:`1px solid ${C.border}`}}>
                  <td style={{padding:"8px 10px",color:C.text,fontSize:12}}>{r.produto}</td>
                  <td style={{padding:"8px 10px",color:C.muted,fontSize:12}}>{r.tamanho}</td>
                  <td style={{padding:"8px 10px",color:C.muted,fontSize:12}}>{r.gola}</td>
                  <td style={{padding:"8px 10px"}}>
                    <div style={{display:"flex",alignItems:"center",gap:6}}>
                      <div style={{width:12,height:12,borderRadius:"50%",background:CORES.find(c=>c.nome===r.cor)?.hex||"#888",border:`1px solid ${C.border}`}}/>
                      <span style={{color:C.muted,fontSize:12}}>{r.cor}</span>
                    </div>
                  </td>
                  <td style={{padding:"8px 10px",color:r.estampaLabel==="Pink"?C.pink:C.muted,fontSize:12,fontWeight:r.estampaLabel==="Pink"?700:400}}>{r.estampaLabel}</td>
                  <td style={{padding:"8px 10px",color:C.green,fontWeight:800}}>{r.quantidade}</td>
                </tr>
              ))
            }
          </tbody>
        </table>
      </div>

      {/* Pedidos individuais */}
      <SectionTitle>Pedidos individuais</SectionTitle>
      {pedidos.length===0
        ?<div style={{color:C.muted,fontSize:13}}>Nenhum pedido registrado.</div>
        :pedidos.map(p=>(
          <Card key={p.id} style={{marginBottom:10,border:`1px solid ${p.pago?C.green:C.border}`}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8,flexWrap:"wrap",gap:8}}>
              <div>
                <span style={{fontWeight:700,color:C.text,fontSize:14}}>{p.nome}</span>
                {p.tel&&<span style={{color:C.muted,fontSize:11,marginLeft:8}}>{p.tel}</span>}
                <span style={{color:C.muted,fontSize:11,marginLeft:8}}>{p.equipe}</span>
              </div>
              <div style={{display:"flex",gap:8,alignItems:"center"}}>
                <span style={{color:C.green,fontWeight:800,fontSize:14}}>R$ {p.total.toFixed(2).replace(".",",")}</span>
                <button onClick={()=>onTogglePago(p.id)} style={{
                  background:p.pago?`${C.green}22`:`${C.pink}11`,
                  border:`1px solid ${p.pago?C.green:C.border}`,
                  color:p.pago?C.green:C.muted,
                  borderRadius:8,padding:"4px 12px",cursor:"pointer",fontSize:11,fontWeight:700,
                }}>{p.pago?"✓ Pago":"Pendente"}</button>
                <span style={{color:C.muted,fontSize:10}}>{new Date(p.data).toLocaleDateString("pt-BR")}</span>
              </div>
            </div>
            <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
              {p.itens.map(item=>(
                <div key={item.id} style={{
                  background:C.card2,border:`1px solid ${item.estampa==="Pink"?C.pink:C.border}`,
                  borderRadius:8,padding:"4px 10px",fontSize:11,color:C.muted,
                }}>
                  {item.quantidade}× {item.produto} {item.tamanho} · {item.gola} · {item.cor}
                  {item.cor==="Preto"&&<span style={{color:item.estampa==="Pink"?C.pink:C.muted}}> · {item.estampa}</span>}
                </div>
              ))}
            </div>
          </Card>
        ))
      }

      {/* Modais */}
      {[
        {show:showReset, onClose:()=>setShowReset(false), title:"🗑 Resetar etapa", color:C.pink,
         body:<>
           <div style={{fontSize:13,color:C.muted,marginBottom:16,lineHeight:1.6}}>Todos os pedidos da <strong style={{color:C.text}}>{etapa}ª etapa</strong> serão apagados. Digite a senha do dirigente.</div>
           <input type="password" value={senhaReset} onChange={e=>setSenhaReset(e.target.value)} onKeyDown={e=>e.key==="Enter"&&confirmarReset()} style={{...inp,marginBottom:6}} placeholder="••••••••" autoFocus/>
           {errReset&&<div style={{color:C.pink,fontSize:12,marginBottom:8}}>Senha incorreta.</div>}
         </>, onConfirm:confirmarReset, confirmLabel:"Apagar tudo"},

        {show:showTimer, onClose:()=>setShowTimer(false), title:"📅 Prazo de encerramento", color:C.green,
         body:<>
           <div style={{fontSize:12,color:C.muted,marginBottom:14,lineHeight:1.6}}>Quando atingir a data/hora, novos pedidos são bloqueados automaticamente.</div>
           <label style={{fontSize:10,color:C.muted,display:"block",marginBottom:5,letterSpacing:1,fontWeight:700}}>DATA E HORA</label>
           <input type="datetime-local" value={timerInput} onChange={e=>setTimerInput(e.target.value)} style={{...inp,marginBottom:12}}/>
           <input type="password" value={senhaTimer} onChange={e=>setSenhaTimer(e.target.value)} onKeyDown={e=>e.key==="Enter"&&salvarTimer()} style={{...inp,marginBottom:6}} placeholder="Senha do dirigente"/>
           {errSenhaTimer&&<div style={{color:C.pink,fontSize:12,marginBottom:8}}>Senha incorreta.</div>}
           {timerAtivo&&<button onClick={cancelarTimer} style={{background:`${C.pink}22`,color:C.pink,border:`1px solid ${C.pink}55`,borderRadius:8,padding:"8px 14px",cursor:"pointer",fontWeight:700,fontSize:12,marginBottom:8,width:"100%"}}>🗑 Remover prazo</button>}
         </>, onConfirm:salvarTimer, confirmLabel:"Salvar"},

        {show:showLockModal, onClose:()=>setShowLockModal(false), title:lockTarget?`🔒 Travar — ${lockTarget}ª Etapa`:"🔓 Destravar", color:C.blue,
         body:<>
           <div style={{fontSize:12,color:C.muted,marginBottom:14,lineHeight:1.6}}>
             {lockTarget?`Participantes serão direcionados obrigatoriamente para a ${lockTarget}ª etapa.`:"Participantes poderão trocar livremente."}
           </div>
           <input type="password" value={senhaLock} onChange={e=>setSenhaLock(e.target.value)} onKeyDown={e=>e.key==="Enter"&&confirmarLock()} style={{...inp,marginBottom:6}} placeholder="Senha do dirigente" autoFocus/>
           {errSenhaLock&&<div style={{color:C.pink,fontSize:12,marginBottom:8}}>Senha incorreta.</div>}
         </>, onConfirm:confirmarLock, confirmLabel:"Confirmar"},
      ].map(({show,onClose,title,color,body,onConfirm,confirmLabel})=>show&&(
        <div key={title} style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
          <div style={{background:C.card,border:`1px solid ${color}55`,borderRadius:16,padding:28,maxWidth:380,width:"90%",boxShadow:glow(color)}}>
            <div style={{fontSize:16,fontWeight:800,color,marginBottom:16}}>{title}</div>
            {body}
            <div style={{display:"flex",gap:8,marginTop:16}}>
              <GhostBtn onClick={onClose} style={{flex:1}}>Cancelar</GhostBtn>
              <PrimaryBtn onClick={onConfirm} color={color} style={{flex:1}}>{confirmLabel}</PrimaryBtn>
            </div>
          </div>
        </div>
      ))}

      {/* Modal trocar senha */}
      {showTrocarSenha&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1001}}>
          <div style={{background:C.card,border:`1px solid ${C.green}55`,borderRadius:16,padding:28,maxWidth:380,width:"90%",boxShadow:glow(C.green)}}>
            <div style={{fontSize:16,fontWeight:800,color:C.green,marginBottom:16}}>🔑 Trocar senha</div>
            <div style={{display:"flex",gap:8,marginBottom:16}}>
              {[{id:"admin",label:"👫 Casal Compras",color:C.accent},{id:"dir",label:"🎯 Dirigente",color:C.blue}].map(t=>(
                <button key={t.id} onClick={()=>{setTipoTroca(t.id);setErrTroca("");}} style={{
                  flex:1,padding:"8px",borderRadius:8,fontWeight:700,fontSize:11,cursor:"pointer",
                  background:tipoTroca===t.id?`${t.color}33`:`${C.border}22`,
                  color:tipoTroca===t.id?t.color:C.muted,
                  border:`1px solid ${tipoTroca===t.id?t.color:C.border}`,
                }}>{t.label}</button>
              ))}
            </div>
            {[{label:"SENHA ATUAL",val:senhaAtual,set:setSenhaAtual},{label:"NOVA SENHA",val:senhaNova,set:setSenhaNova},{label:"CONFIRMAR",val:senhaNovaConf,set:setSenhaNovaConf}].map(f=>(
              <div key={f.label} style={{marginBottom:10}}>
                <label style={{fontSize:9,color:C.muted,display:"block",marginBottom:4,letterSpacing:1,fontWeight:700}}>{f.label}</label>
                <input type="password" value={f.val} onChange={e=>f.set(e.target.value)} style={inp} placeholder="••••••••"/>
              </div>
            ))}
            {errTroca&&<div style={{color:C.pink,fontSize:12,marginBottom:8}}>⚠ {errTroca}</div>}
            {okTroca&&<div style={{color:C.green,fontSize:12,marginBottom:8,fontWeight:700}}>✓ Senha alterada!</div>}
            <div style={{display:"flex",gap:8,marginTop:14}}>
              <GhostBtn onClick={()=>setShowTrocarSenha(false)} style={{flex:1}}>Cancelar</GhostBtn>
              <PrimaryBtn onClick={confirmarTroca} color={C.green} style={{flex:1}}>Salvar</PrimaryBtn>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── App ───────────────────────────────────────────────────────────
export default function App() {
  const [aba,setAba]             = useState("catalogo");
  const [etapa,setEtapaState]    = useState(1);
  const [pedidos,setPedidos]     = useState([]);
  const [etapaLock,setEtapaLock] = useState("");
  const [agora,setAgora]         = useState(new Date());
  const [timerVal,setTimerVal]   = useState("");
  const [loading,setLoading]     = useState(true);

  // Load config from Supabase on mount and when etapa changes
  useEffect(()=>{
    async function loadAll() {
      setLoading(true);
      try {
        const [lock, timer1, timer2] = await Promise.all([
          getConfig("etapa_lock"),
          getConfig("timer_etapa1"),
          getConfig("timer_etapa2"),
        ]);
        const activeEtapa = lock ? parseInt(lock) : 1;
        setEtapaLock(lock||"");
        setEtapaState(activeEtapa);
        setTimerVal(activeEtapa===1 ? timer1 : timer2);
        const peds = await getPedidos(activeEtapa);
        setPedidos(peds);
      } catch(e) { console.error(e); }
      setLoading(false);
    }
    loadAll();
    const iv = setInterval(()=>setAgora(new Date()), 10000);
    return ()=>clearInterval(iv);
  }, []);

  const mudarEtapa = async (e) => {
    setEtapaState(e);
    const peds = await getPedidos(e);
    setPedidos(peds);
    const t = await getConfig(`timer_etapa${e}`);
    setTimerVal(t||"");
  };

  const reload = async () => {
    const peds = await getPedidos(etapa);
    setPedidos(peds);
  };

  const togglePago = async (id) => {
    const p = pedidos.find(x=>x.id===id);
    if(!p) return;
    const novoPago = !p.pago;
    await updatePedidoPago(id, novoPago);
    setPedidos(pedidos.map(x=>x.id===id?{...x,pago:novoPago}:x));
  };

  const pedidosEncerrados = timerVal ? new Date()>=new Date(timerVal) : false;
  const equipes = etapa===1 ? EQUIPES_ETAPA1 : EQUIPES_ETAPA2;
  const abas=[{id:"catalogo",icon:"👕",label:"Catálogo"},{id:"pedido",icon:"✏️",label:"Pedido"},{id:"admin",icon:"🔐",label:"Coord."}];

  if(loading) return (
    <div style={{minHeight:"100vh",background:C.bg,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:16}}>
      <div style={{fontSize:48}}>✝️</div>
      <div style={{color:C.accent,fontWeight:800,fontSize:18,letterSpacing:2}}>EJC MEDEIROS</div>
      <div style={{color:C.muted,fontSize:13}}>Carregando...</div>
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:C.bg,color:C.text,fontFamily:"'Trebuchet MS', sans-serif"}}>
      {/* Fundo decorativo */}
      <div style={{position:"fixed",inset:0,pointerEvents:"none",overflow:"hidden",zIndex:0}}>
        <div style={{position:"absolute",top:-100,right:-100,width:400,height:400,borderRadius:"50%",background:`radial-gradient(circle, ${C.accent}15 0%, transparent 70%)`}}/>
        <div style={{position:"absolute",bottom:-100,left:-100,width:300,height:300,borderRadius:"50%",background:`radial-gradient(circle, ${C.blue}10 0%, transparent 70%)`}}/>
        <div style={{position:"absolute",top:"40%",left:"60%",width:200,height:200,borderRadius:"50%",background:`radial-gradient(circle, ${C.pink}08 0%, transparent 70%)`}}/>
      </div>

      {/* Header */}
      <div style={{position:"sticky",top:0,zIndex:100,background:`${C.bg}EE`,backdropFilter:"blur(12px)",borderBottom:`1px solid ${C.border}`}}>
        <div style={{maxWidth:960,margin:"0 auto",padding:"0 20px"}}>
                    {/* Topo */}
          <div style={{display:"flex",alignItems:"center",gap:12,padding:"12px 0 10px"}}>
            <img src={LOGO} alt="EJC" style={{width:50,height:50,objectFit:"contain",filter:"drop-shadow(0 0 10px rgba(255,107,53,0.5))",borderRadius:8}}/>
            <div>
              <div style={{fontSize:9,letterSpacing:4,color:C.accent,fontWeight:800,textTransform:"uppercase",marginBottom:2}}>
                Encontro de Jovens com Cristo
              </div>
              <div style={{fontSize:20,fontWeight:800,color:C.white,letterSpacing:-0.5}}>
                EJC <span style={{color:C.accent}}>Medeiros</span>
              </div>
            </div>
          </div>

          {/* Qual etapa box */}
          <div style={{background:`${C.accent}12`,border:`1px solid ${C.accent}33`,borderRadius:10,padding:"10px 14px",marginBottom:12}}>
            <div style={{fontSize:10,fontWeight:800,letterSpacing:2,color:C.accent,marginBottom:6}}>📋 QUAL ETAPA DO ENCONTRO?</div>
            <div style={{display:"flex",gap:8}}>
              {[1,2].map(e=>{
                const isActive=etapa===e;
                const otherLocked=etapaLock&&etapaLock!==String(e);
                return (
                  <button key={e} onClick={()=>!otherLocked&&mudarEtapa(e)} style={{
                    flex:1,
                    background:isActive?C.accent:"transparent",
                    color:isActive?C.white:otherLocked?C.border:C.muted,
                    border:`2px solid ${isActive?C.accent:otherLocked?C.border:C.border}`,
                    borderRadius:10,padding:"10px 8px",cursor:otherLocked?"not-allowed":"pointer",
                    fontWeight:800,fontSize:14,
                    boxShadow:isActive?glow(C.accent):"none",
                    transition:"all .15s",
                  }}>
                    {isActive?"✓ ":""}{e}ª Etapa{etapaLock===String(e)?" 🔒":""}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Abas */}
          <div style={{display:"flex",gap:0}}>
            {abas.map(a=>(
              <button key={a.id} onClick={()=>setAba(a.id)} style={{
                background:"none",border:"none",cursor:"pointer",
                padding:"10px 16px",fontSize:11,fontWeight:800,letterSpacing:1.5,
                color:aba===a.id?C.accent:C.muted,
                borderBottom:`2px solid ${aba===a.id?C.accent:"transparent"}`,
                marginBottom:-1,transition:"all .15s",
                display:"flex",alignItems:"center",gap:5,
              }}>
                <span>{a.icon}</span> {a.label.toUpperCase()}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Conteúdo */}
      <div style={{maxWidth:960,margin:"0 auto",padding:"28px 20px",position:"relative",zIndex:1}}>
        {aba==="catalogo"&&<><CatalogoCores/><CatalogoPecas/><CatalogoTabela/></>}
        {aba==="pedido"  &&<FormPedido onPedidoAdicionado={reload} etapa={etapa} equipes={equipes} encerrado={pedidosEncerrados} prazoInfo={timerVal}/>}
        {aba==="admin"   &&<PainelAdmin pedidos={pedidos} etapa={etapa} onLimpar={reload} onTogglePago={togglePago} savePedidos={savePedidos} etapaLock={etapaLock} onLockChange={(v)=>{setEtapaLock(v);}}/>}
      </div>
    </div>
  );
}
